if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const data = $input.first().json;
const target = data.target || 'Unknown Opportunity';
const agency = data.agency || 'Unknown Agency';
const value = data.value || 'Unknown';
const pipeline = $('Get Pipeline Context').all().map(i => i.json);
const pipelineSummary = pipeline.map((o,i) => `${i+1}. ${o.opp_title} | ${o.agency} | Score: ${o.gda_score} | $${(o.estimated_value||0).toLocaleString()}`).join('
');

const prompt = `You are playing the role of a BLACK HAT competitor analyst for Georgetown Defense Analytics (GDA). Your job is to think adversarially: if you were a competitor trying to WIN this contract AGAINST GDA, what would you do?

TARGET OPPORTUNITY: ${target}
AGENCY: ${agency}
ESTIMATED VALUE: ${value}

GDA CURRENT PIPELINE (for context on what they are pursuing):
${pipelineSummary || 'No pipeline data'}

As a BLACK HAT analyst, identify:
1. COMPETITOR ADVANTAGES: What can top competitors (BAH, SAIC, Leidos, CACI, Peraton) do better than GDA on this opportunity?
2. GDA WEAKNESSES: What specific GDA vulnerabilities would a competitor exploit? (size, past performance gaps, clearance levels, incumbency, pricing)
3. ATTACK VECTORS: How would a smart competitor position to beat GDA? (teaming, pricing strategy, technical differentiation, relationship leveraging)
4. COUNTER-STRATEGIES: What should GDA do NOW to neutralize these attacks?
5. BID/NO-BID SIGNAL: Given the competitive landscape, should GDA pursue aggressively, cautiously, or no-bid?

Return ONLY this JSON (no markdown):
{
  "target": "${target}",
  "agency": "${agency}",
  "top_competitors": [{"name": "", "threat_level": "HIGH/MEDIUM/LOW", "attack_strategy": "", "key_advantage": ""}],
  "gda_vulnerabilities": [{"area": "", "severity": "CRITICAL/HIGH/MEDIUM", "detail": ""}],
  "attack_vectors": ["specific attack strategy 1", "specific attack strategy 2", "specific attack strategy 3"],
  "counter_strategies": ["counter action 1", "counter action 2", "counter action 3"],
  "bid_signal": "PURSUE/CAUTIOUS/NO-BID",
  "bid_rationale": "1-2 sentence rationale",
  "win_theme_gaps": ["gap 1", "gap 2"],
  "confidence_score": 75,
  "generated_at": "${new Date().toISOString()}"
}`;
return [{json: {prompt, target, agency}}];

const resp = $input.first().json;
const inputData = $('Build Black Hat Prompt').first().json;
try {
  const text = resp.content[0].text;
  const clean = text.replace(/```json|```/g,'').trim();
  const s = clean.indexOf('{'); const e = clean.lastIndexOf('}');
  const result = JSON.parse(clean.substring(s, e+1));
  return [{json: result}];
} catch(err) {
  return [{json: {target: inputData.target, agency: inputData.agency, bid_signal: 'CAUTIOUS', bid_rationale: 'Analysis failed - manual review required', top_competitors: [], gda_vulnerabilities: [], attack_vectors: [], counter_strategies: [], win_theme_gaps: [], confidence_score: 0, error: err.message, generated_at: new Date().toISOString()}}];
}
